function addToInput(t,e){const r=document.getElementById(e);r.value+=t.value}function clearInput(t){const e=document.getElementById(t);e.value=""}function deleteLastChar(t){const e=document.getElementById(t);e.value=e.value.slice(0,-1)}function incrementValue(t){const e=document.getElementById(t),r=parseInt(e.value,10);e.value=r+1}function decrementValue(t){const e=document.getElementById(t),r=parseInt(e.value,10);r>1?e.value=r-1:e.value=1}function initFileDropzones(){document.querySelectorAll(".file-dropzone").forEach(t=>{const e=t.querySelector(".file-dropzone__input"),r=t.querySelector(".file-dropzone__preview");e&&(t.addEventListener("click",n=>{n.target!==e&&e.click()}),t.addEventListener("dragenter",n=>{n.preventDefault(),t.classList.add("file-dropzone--dragover")}),t.addEventListener("dragover",n=>{n.preventDefault(),t.classList.add("file-dropzone--dragover")}),t.addEventListener("dragleave",n=>{n.preventDefault(),t.classList.remove("file-dropzone--dragover")}),t.addEventListener("drop",n=>{n.preventDefault(),t.classList.remove("file-dropzone--dragover"),n.dataTransfer.files.length>0&&(e.files=n.dataTransfer.files,updateFilePreview(r,e.files),e.dispatchEvent(new Event("change",{bubbles:!0})))}),e.addEventListener("change",()=>{updateFilePreview(r,e.files)}))})}function updateFilePreview(t,e){t&&(e.length===0?t.textContent="":e.length===1?t.textContent=e[0].name:t.textContent=`${e.length} files selected`)}document.addEventListener("DOMContentLoaded",initFileDropzones);
